// JWT Validation — pure JS, no Node built-ins
// n8n sandbox blocks 'crypto' but allows manual bit operations

const SECRET = 'clawops-workshop-secret-change-in-prod';

const headers = $input.first().json.headers || {};
const authHeader = headers['authorization'] || headers['Authorization'] || '';
const token = authHeader.startsWith('Bearer ') ? authHeader.slice(7) : '';

if (!token) throw new Error('No JWT token — request rejected');

const parts = token.split('.');
if (parts.length !== 3) throw new Error('Invalid JWT format');

const [headerB64, payloadB64, sigB64] = parts;

// ── Pure-JS HMAC-SHA256 ──────────────────────────────────────
function strToBytes(s) {
  const b = [];
  for (let i = 0; i < s.length; i++) b.push(s.charCodeAt(i) & 0xff);
  return b;
}

function sha256(data) {
  // SHA-256 constants
  const K = [
    0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,
    0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,
    0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,
    0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,
    0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,
    0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,
    0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,
    0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2
  ];
  let h = [0x6a09e667,0xbb67ae85,0x3c6ef372,0xa54ff53a,0x510e527f,0x9b05688c,0x1f83d9ab,0x5be0cd19];
  const msg = data.slice();
  const bitLen = msg.length * 8;
  msg.push(0x80);
  while ((msg.length % 64) !== 56) msg.push(0);
  for (let i = 7; i >= 0; i--) msg.push((bitLen / Math.pow(2, i*8)) & 0xff);
  for (let chunk = 0; chunk < msg.length; chunk += 64) {
    const w = [];
    for (let i = 0; i < 16; i++)
      w[i] = (msg[chunk+i*4]<<24)|(msg[chunk+i*4+1]<<16)|(msg[chunk+i*4+2]<<8)|msg[chunk+i*4+3];
    for (let i = 16; i < 64; i++) {
      const s0 = ((w[i-15]>>>7)|(w[i-15]<<25))^((w[i-15]>>>18)|(w[i-15]<<14))^(w[i-15]>>>3);
      const s1 = ((w[i-2]>>>17)|(w[i-2]<<15))^((w[i-2]>>>19)|(w[i-2]<<13))^(w[i-2]>>>10);
      w[i] = (w[i-16]+s0+w[i-7]+s1) >>> 0;
    }
    let [a,b,c,d,e,f,g,hh] = h;
    for (let i = 0; i < 64; i++) {
      const S1 = ((e>>>6)|(e<<26))^((e>>>11)|(e<<21))^((e>>>25)|(e<<7));
      const ch = (e&f)^(~e&g);
      const t1 = (hh+S1+ch+K[i]+w[i])>>>0;
      const S0 = ((a>>>2)|(a<<30))^((a>>>13)|(a<<19))^((a>>>22)|(a<<10));
      const maj = (a&b)^(a&c)^(b&c);
      const t2 = (S0+maj)>>>0;
      hh=g; g=f; f=e; e=(d+t1)>>>0; d=c; c=b; b=a; a=(t1+t2)>>>0;
    }
    h = h.map((v,i)=>(v+[a,b,c,d,e,f,g,hh][i])>>>0);
  }
  return h.reduce((acc,v)=>acc+v.toString(16).padStart(8,'0'),'');
}

function hmacSha256(key, msg) {
  let keyBytes = strToBytes(key);
  if (keyBytes.length > 64) keyBytes = hexToBytes(sha256(keyBytes));
  while (keyBytes.length < 64) keyBytes.push(0);
  const iPad = keyBytes.map(b => b ^ 0x36);
  const oPad = keyBytes.map(b => b ^ 0x5c);
  const inner = sha256([...iPad, ...strToBytes(msg)]);
  return sha256([...oPad, ...hexToBytes(inner)]);
}

function hexToBytes(h) {
  const b = [];
  for (let i = 0; i < h.length; i+=2) b.push(parseInt(h.slice(i,i+2),16));
  return b;
}

function b64urlEncode(bytes) {
  let b = '';
  bytes.forEach(v => b += String.fromCharCode(v));
  return btoa(b).replace(/\+/g,'-').replace(/\//g,'_').replace(/=/g,'');
}

// Verify signature
const sig = b64urlEncode(hexToBytes(hmacSha256(SECRET, `${headerB64}.${payloadB64}`)));
if (sig !== sigB64) throw new Error('Invalid JWT signature — request rejected');

// Check expiry
const payload = JSON.parse(atob(payloadB64.replace(/-/g,'+').replace(/_/g,'/')));
const now = Math.floor(Date.now() / 1000);
if (!payload.exp || payload.exp < now) {
  throw new Error(`JWT expired ${now - payload.exp}s ago — replay attack prevented`);
}

// Pass through with claims attached
const body = $input.first().json.body || $input.first().json;
return [{ json: { ...body, _jwt_verified: true, _jwt_claims: payload } }];

const body = $input.first().json.body || $input.first().json;
const ev = body.event || body;

// Skip info events
if (!['error','warn'].includes(ev.severity)) {
  return [];  // empty = stop flow
}

// Validate we have real event data
if (!ev.deploy && !ev.name && !ev.reason) {
  return [];  // malformed event — stop
}

// Deduplicate by deploy (not pod name — pod names change on restart)
const store = $getWorkflowStaticData('global');
if (!store.dedup) store.dedup = {};
const key = `${ev.reason}:${ev.deploy || ev.name}:${ev.namespace}`;
const now = Date.now();
if (store.dedup[key] && (now - store.dedup[key]) < 300000) {
  return [];  // deduplicated — stop flow silently
}
store.dedup[key] = now;

// Cleanup
Object.keys(store.dedup).forEach(k => {
  if (now - store.dedup[k] > 600000) delete store.dedup[k];
});

return [{ json: {
  skip: false,
  severity: ev.severity,
  namespace: ev.namespace || 'workshop',
  kind: ev.kind || 'Pod',
  name: ev.name || '',
  reason: ev.reason || '',
  message: ev.message || '',
  deploy: ev.deploy || (ev.name || '').split('-').slice(0,-2).join('-') || ev.name || '',
  node: ev.node || '',
  ts: ev.ts || new Date().toISOString(),
  count: ev.count || 1,
  reasons: ev.reasons || [ev.reason]
}}];

